mapper.select:
SELECT *
FROM store
WHERE store_idx = #{storeIdx}
  AND owner_member_idx = #{ownerMemberIdx}

mapper.delete:
DELETE FROM store
WHERE store_idx = #{storeIdx}
  AND owner_member_idx = #{ownerMemberIdx}

mapper.update:
UPDATE store
SET store_status = #{storeStatus}
WHERE store_idx = #{storeIdx}
  AND owner_member_idx = #{ownerMemberIdx}
